[350] يُنظر: ((تفسير ابن جرير)) (21/383، 386)، ((تفسير ابن كثير)) (7/385)، ((نظم الدرر)) للبقاعي (18/382)، ((تفسير السعدي)) (ص: 802)، ((تفسير ابن عاشور)) (26/258)، ((أضواء البيان)) للشنقيطي (7/417). قال السعدي: (لو استقلَّ كلُّ واحدٍ منهم بنفْسِه لم يحصُلْ بذلك التَّعارُفُ الَّذي يترتَّبُ عليه التَّناصُرُ والتَّعاوُنُ، والتَّوارُثُ، والقيامُ بحُقوقِ الأقارِبِ، ولكِنَّ اللهَ جعَلهم شُعوبًا وقبائلَ؛ لأجْلِ أن تَحصُلَ هذه الأمورُ وغَيرُها مِمَّا يتوقَّفُ على التَّعارُفِ، ولُحوقِ الأنسابِ). ((تفسير السعدي)) (ص: 802). وقال القَلْقَشَنْدي: (قد عدَّ أهلُ اللُّغةِ طبَقاتِ الأنسابِ سِتَّ طبَقاتٍ: الطَّبقةُ الأولى: الشَّعبُ، بفتحِ العَينِ، وهو النَّسبُ الأبعَدُ؛ كعَدْنانَ مثلًا... الطَّبقةُ الثَّانيةُ: القَبيلةُ، وهي ما انقسَمَ فيه الشَّعبُ؛ كرَبيعةَ ومُضَرَ... الطَّبقةُ الثَّالثةُ: العِمارةُ، بكسرِ العَينِ المُهمَلةِ، وهي ما انقسَم فيه أنسابُ القَبيلةِ؛ كقُرَيشٍ وكِنانةَ. وتُجمَعُ على عِماراتٍ، وعَمائرَ. الطَّبقةُ الرَّابعةُ: البَطنُ، وهي ما انقسَم فيه أقسامُ العِمارةِ؛ كبَني عبدِ مَنافٍ، وبَني مَخزومٍ. ويُجمعُ: على بُطونٍ، وأبْطُنٍ. الطَّبقةُ الخامِسةُ: الفَخِذُ، وهي ما انقسَم فيه أقسامُ البَطنِ؛ كبَني هاشمٍ، وبني أُمَيَّةَ. وتُجمعُ على: أفخاذٍ. الطَّبقةُ السَّادسةُ: الفَصيلةُ، بالصَّادِ المُهمَلةِ، وهي ما انقسَم فيه أقسامُ الفَخِذِ؛ كبَني العبَّاسِ... وبالجُملةِ فالفَخِذُ يَجمَعُ الفصائلَ، والبطنُ يجمعُ الأفخاذَ، والعِمارةُ يجمعُ البُطونَ، والقبيلةُ تَجمعُ العَمائرَ، والشَّعبُ يجمعُ القبائلَ... وزاد بعضُهم العَشيرةَ قبْلَ الفَصيلةِ). ((قلائد الجمان في التعريف بقبائل عرب الزمان)) (ص: 14). ويُنظر: ((الأحكام السلطانية)) للماوَرْدي (ص: 304)، ((تفسير الزمخشري)) (4/374). وقال الشنقيطي: (ولم يُذكَرْ مِن هذه السِّتِّ في القرآنِ إلَّا ثلاثٌ: الشُّعوبُ والقَبائلُ كما في هذه الآيةِ، والفَصيلةُ في المَعارِجِ، في قولِه: وَفَصِيلَتِهِ الَّتِي تُؤْوِيهِ
[المعارج: 13]
). ((أضواء البيان)) (7/418).

[476] يُنظر: ((تفسير ابن جرير)) (21/388، 392)، ((درء تعارض العقل والنقل)) لابن تيميَّة (7/436)، ((بدائع الفوائد)) لابن القيم (4/17)، ((تفسير ابن كثير)) (7/389، 390)، ((جامع العلوم والحكم)) لابن رجب (1/109، 110)، ((تفسير السعدي)) (ص: 802)، ((تفسير ابن عاشور)) (26/264)، ((تفسير ابن عثيمين: سورة الحجرات - الحديد)) (ص: 60). قال الشنقيطي: (وقولُه تعالى في هذه الآيةِ الكريمةِ: قَالَتِ الْأَعْرَابُ المرادُ به بعضُ الأعرابِ... وإنَّما قُلْنا: إنَّ المرادَ بعضُ الأعرابِ في هذه الآيةِ؛ لأنَّ اللهَ بيَّنَ في موضعٍ آخَرَ أنَّ مِنهم مَن ليس كذلك، وذلك في قولِه تعالى: وَمِنَ الْأَعْرَابِ مَنْ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآَخِرِ وَيَتَّخِذُ مَا يُنْفِقُ قُرُبَاتٍ عِنْدَ اللَّهِ وَصَلَوَاتِ الرَّسُولِ أَلَا إِنَّهَا قُرْبَةٌ لَهُمْ سَيُدْخِلُهُمُ اللَّهُ فِي رَحْمَتِهِ إِنَّ اللَّهَ غَفُورٌ رَحِيمٌ
[التوبة: 99]
). ((أضواء البيان)) (7/420). قيل: إنَّ هؤلاء الأعرابَ لم يَكونوا منافِقينَ، استظهَر ذلك ابنُ تيميَّةَ، ونسَبه للأكثَرينَ، وذهَب إليه ابنُ القيِّم، وابنُ كثير، وابنُ رجب. يُنظر: ((مجموع الفتاوى)) لابن تيمية (28/44)، ((درء تعارض العقل والنقل)) لابن تيمية (7/436)، ((بدائع الفوائد)) لابن القيم (4/17)، ((تفسير ابن كثير)) (7/389)، ((جامع العلوم والحكم)) لابن رجب (1/109، 110). وممَّن قال بنحوِ هذا القولِ مِن السَّلفِ: ابنُ عبَّاسٍ، والزُّهْريُّ، وابنُ زَيدٍ، وإبراهيمُ النَّخَعيُّ. يُنظر: ((تفسير ابن جرير)) (21/389)، ((تفسير الماوردي)) (5/337)، ((تفسير ابن كثير)) (7/389). قال ابنُ القيِّم: (هؤلاء مُسلِمونَ، وليسوا بمؤمِنينَ؛ لأنَّهم لَيسوا ممَّن باشَر الإيمانُ قلْبَه، فذاق حلاوتَه وطَعْمَه، وهذا حالُ أكثَرِ المُنتَسِبينَ إلى الإسلامِ، وليس هؤلاء كُفَّارًا؛ فإنَّه سبحانه أثبَت لهم الإسلامَ بقَولِه: وَلَكِنْ قُولُوا أَسْلَمْنَا، ولم يُرِدْ: قُولُوا بألسِنَتِكم من غيرِ مُواطأةِ القَلبِ؛ فإنَّه فرَّق بيْنَ قَولِهم: آمَنَّا، وقَولِهم: أسْلَمْنا، ولكِنْ لَمَّا لمْ يَذوقوا طعْمَ الإيمانِ قال: لَمْ تُؤْمِنُوا، ووعَدَهم سُبحانَه وتعالى -مع ذلك- على طاعتِهم ألَّا يَنقُصَهم مِن أُجورِ أعمالِهم شَيئًا). ((مدارج السالكين)) (3/91). ويُنظر: ((الإيمان)) لابن تيمية (ص: 295). وقيل: إنَّ هؤلاء الأعرابَ كانوا مُنافِقينَ. وممَّن ذهب إلى ذلك: البُخاريُّ، ومحمَّدُ بنُ نصرٍ المروزيُّ، والقرطبي، والشنقيطي. يُنظر: ((صحيح البخاري)) (1/14)، ((تعظيم قدر الصلاة)) للمروزي (2/554- 556)، ((تفسير القرطبي)) (16/348)، ((أضواء البيان)) للشنقيطي (7/419، 420). وممَّن قال بهذا القولِ مِن السَّلفِ: قَتادةُ، وسعيدُ بنُ جُبَيرٍ، ومُجاهِدٌ. يُنظر: ((تفسير ابن جرير)) (21/391)، ((تفسير الماوردي)) (5/337)، ((تفسير ابن كثير)) (7/389). قال القرطبي: (معنى وَلَكِنْ قُولُوا أَسْلَمْنَا، أي: استَسْلَمْنا خَوفَ القَتلِ والسَّبْيِ، وهذه صِفةُ المنافِقينَ؛ لأنَّهم أسْلَموا في ظاهِرِ إيمانِهم، ولم تُؤمِنْ قُلوبُهم). ((تفسير القرطبي)) (16/348). وقال الشِّنقيطي: (اللهُ نفى عنهم الإيمانَ دونَ الإسلامِ، ولذلك وَجهانِ مَعروفانِ عند العُلَماءِ؛ أظهَرُهما عندي: أنَّ الإيمانَ المنفيَّ عنهم في هذه الآيةِ هو مُسَمَّاه الشَّرعيُّ الصَّحيحُ، والإسلامَ المُثبَتَ لهم فيها هو الإسلامُ اللُّغَويُّ الَّذي هو الاستِسلامُ والانقيادُ بالجَوارحِ دونَ القَلبِ... وإذا حُمِلَ الإسلامُ في قَولِه: وَلَكِنْ قُولُوا أَسْلَمْنَا انقَدْنا واستَسْلَمْنا بالألسِنةِ والجوارحِ، فلا إشكالَ في الآيةِ، وعلى هذا القَولِ فالأعرابُ المذكورونَ مُنافِقونَ؛ لأنَّهم مُسلِمونَ في الظَّاهِرِ، وهم كُفَّارٌ في الباطِنِ. الوَجهُ الثَّاني: أنَّ المرادَ بنَفْيِ الإيمانِ في قَولِه: لَمْ تُؤْمِنُوا نفْيُ كَمالِ الإيمانِ، لا نَفْيُه مِن أصلِه، وعليه فلا إشكالَ أيضًا؛ لأنَّهم مُسلِمونَ مع أنَّ إيمانَهم غيرُ تامٍّ، وهذا لا إشكالَ فيه عندَ أهلِ السُّنَّةِ والجَماعةِ القائِلينَ بأنَّ الإيمانَ يَزيدُ ويَنقُصُ). ((أضواء البيان)) (7/419).
